// p256Sqrt sets e to a square root of x. If x is not a square, p256Sqrt returns
// false and e is unchanged. e and x can overlap.
internal static bool /*isSquare*/ p256Sqrt(ж<fiat.P256Element> Ꮡe, ж<fiat.P256Element> Ꮡx) {
    bool isSquare = default!;

    var candidate = @new<fiat.P256Element>();
    p256SqrtCandidate(candidate, Ꮡx);
    var square = @new<fiat.P256Element>().Square(candidate);
    if (square.Equal(Ꮡx) != 1) {
        return false;
    }
    Ꮡe.Set(candidate);
    return true;
}

// p256SqrtCandidate sets z to a square root candidate for x. z and x must not overlap.
internal static void p256SqrtCandidate(ж<fiat.P256Element> Ꮡz, ж<fiat.P256Element> Ꮡx) {
    // Since p = 3 mod 4, exponentiation by (p + 1) / 4 yields a square root candidate.
    //
    // The sequence of 7 multiplications and 253 squarings is derived from the
    // following addition chain generated with github.com/mmcloughlin/addchain v0.4.0.
    //
    //	_10       = 2*1
    //	_11       = 1 + _10
    //	_1100     = _11 << 2
    //	_1111     = _11 + _1100
    //	_11110000 = _1111 << 4
    //	_11111111 = _1111 + _11110000
    //	x16       = _11111111 << 8 + _11111111
    //	x32       = x16 << 16 + x16
    //	return      ((x32 << 32 + 1) << 96 + 1) << 94
    //
    ж<fiat.P256Element> t0 = @new<fiat.P256Element>();
    Ꮡz.Square(Ꮡx);
    Ꮡz.Mul(Ꮡx, Ꮡz);
    t0.Square(Ꮡz);
    for (nint s = 1; s < 2; s++) {
        t0.Square(t0);
    }
    Ꮡz.Mul(Ꮡz, t0);
    t0.Square(Ꮡz);
    for (nint s = 1; s < 4; s++) {
        t0.Square(t0);
    }
    Ꮡz.Mul(Ꮡz, t0);
    t0.Square(Ꮡz);
    for (nint s = 1; s < 8; s++) {
        t0.Square(t0);
    }
    Ꮡz.Mul(Ꮡz, t0);
    t0.Square(Ꮡz);
    for (nint s = 1; s < 16; s++) {
        t0.Square(t0);
    }
    Ꮡz.Mul(Ꮡz, t0);
    for (nint s = 0; s < 32; s++) {
        Ꮡz.Square(Ꮡz);
    }
    Ꮡz.Mul(Ꮡx, Ꮡz);
    for (nint s = 0; s < 96; s++) {
        Ꮡz.Square(Ꮡz);
    }
    Ꮡz.Mul(Ꮡx, Ꮡz);
    for (nint s = 0; s < 94; s++) {
        Ꮡz.Square(Ꮡz);
    }
}

} // end nistec_package
